inputs.customToolFunc:
const axios = require('axios');
const FormData = require('form-data');

const fileUrl = $fileUrl;
const filename = $filename;

try {
  // Download the file from Jira
  const fileResponse = await axios.get(fileUrl, {
    responseType: 'arraybuffer',
    headers: {
      'Authorization': 'Basic ' + Buffer.from(($vars?.ATLASSIAN_EMAIL || '') + ':' + ($vars?.ATLASSIAN_TOKEN || '')).toString('base64')
    },
    timeout: 30000
  });

  const fileBuffer = Buffer.from(fileResponse.data);

  // Try Unstructured.io first
  const unstructuredKey = $vars?.UNSTRUCTURED_API_KEY;
  if (unstructuredKey) {
    const form = new FormData();
    form.append('files', fileBuffer, { filename: filename });
    form.append('strategy', 'hi_res');

    const ocrResponse = await axios.post(
      $vars?.UNSTRUCTURED_API_URL || 'https://api.unstructured.io/general/v0/general',
      form,
      {
        headers: {
          ...form.getHeaders(),
          'unstructured-api-key': unstructuredKey
        },
        maxBodyLength: Infinity,
        timeout: 120000
      }
    );

    const elements = ocrResponse.data || [];
    const text = elements.filter(el => el.text && el.text.trim()).map(el => el.text.trim()).join('\n');
    return `OCR_SOURCE: unstructured.io\nELEMENTS: ${elements.length}\nCONFIDENCE: Complete\n\n${text}`;
  }

  // Fallback: pdf-parse for PDFs
  const ext = filename.toLowerCase().split('.').pop();
  if (ext === 'pdf') {
    const pdfParse = require('pdf-parse');
    const data = await pdfParse(fileBuffer);
    return `OCR_SOURCE: pdf-parse (local fallback)\nPAGES: ${data.numpages}\nCONFIDENCE: Partial\n\n${data.text}`;
  }

  return `OCR_SOURCE: none\nCONFIDENCE: Failed\nERROR: No OCR provider available for file type .${ext}. Set UNSTRUCTURED_API_KEY for image OCR.`;

} catch (error) {
  return `OCR_SOURCE: error\nCONFIDENCE: Failed\nERROR: ${error.message}`;
}

